import{initTocToggle}from"../tools/tocToggle.js";import{main}from"../main.js";function initTOC(){const t={navItems:document.querySelectorAll(".post-toc-wrap .post-toc li"),updateActiveTOCLink(){if(Array.isArray(t.sections)){let e=t.sections.findIndex(e=>e&&0<e.getBoundingClientRect().top-100);-1===e?e=t.sections.length-1:0<e&&e--,this.activateTOCLink(e)}},registerTOCScroll(){t.sections=[...document.querySelectorAll(".post-toc li a.nav-link")].map(e=>{return document.getElementById(decodeURI(e.getAttribute("href")).replace("#",""))})},activateTOCLink(e){const t=document.querySelectorAll(".post-toc li a.nav-link")[e];if(t&&!t.classList.contains("active-current")){document.querySelectorAll(".post-toc .active").forEach(e=>{e.classList.remove("active","active-current")}),t.classList.add("active","active-current");const n=document.querySelector(".toc-content-container");var e=n.getBoundingClientRect().top,o=n.offsetHeight>window.innerHeight?(n.offsetHeight-window.innerHeight)/2:0,e=t.getBoundingClientRect().top-e-Math.max(document.documentElement.clientHeight,window.innerHeight||0)/2+t.offsetHeight/2-o,o=n.scrollTop+e;n.scrollTo({top:o,behavior:"smooth"})}},showTOCAside(){var e=()=>{const e=main.getStyleStatus();var t="isOpenPageAside";e&&e.hasOwnProperty(t)?initTocToggle().pageAsideHandleOfTOC(e[t]):initTocToggle().pageAsideHandleOfTOC(!0)},t="init_open";!theme.articles.toc.hasOwnProperty(t)||theme.articles.toc[t]?e():initTocToggle().pageAsideHandleOfTOC(!1)}};return 0<t.navItems.length?(t.showTOCAside(),t.registerTOCScroll()):document.querySelectorAll(".toc-content-container, .toc-marker").forEach(e=>{e.remove()}),t}try{swup.hooks.on("page:view",()=>{initTOC()})}catch(e){}document.addEventListener("DOMContentLoaded",initTOC);export{initTOC};